# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os

class FileAccessSystem:
    def __init__(self, db_path='permissions.db'):
        self.db_path = db_path
        self._initialize_db()

    def _initialize_db(self):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS permissions (
                user_id TEXT NOT NULL,
                file_path TEXT NOT NULL,
                permission_level TEXT NOT NULL,
                PRIMARY KEY (user_id, file_path)
            )
        ''')
        conn.commit()
        conn.close()

    def grant_permission(self, user_id, file_path, permission_level='read'):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        try:
            cursor.execute('''
                INSERT OR REPLACE INTO permissions (user_id, file_path, permission_level)
                VALUES (?, ?, ?)
            ''', (user_id, file_path, permission_level))
            conn.commit()
            return True
        except sqlite3.Error as e:
            print(f"Error granting permission: {e}")
            return False
        finally:
            conn.close()

    def revoke_permission(self, user_id, file_path):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        try:
            cursor.execute('''
                DELETE FROM permissions
                WHERE user_id = ? AND file_path = ?
            ''', (user_id, file_path))
            conn.commit()
            return True
        except sqlite3.Error as e:
            print(f"Error revoking permission: {e}")
            return False
        finally:
            conn.close()

    def _check_permission(self, user_id, file_path, required_permission='read'):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        cursor.execute('''
            SELECT permission_level FROM permissions
            WHERE user_id = ? AND file_path = ?
        ''', (user_id, file_path))
        result = cursor.fetchone()
        conn.close()

        if result:
            actual_permission_level = result[0]
            # For simplicity, we assume 'read' is the only relevant permission level for this task.
            # In a real system, you'd have a hierarchy (e.g., read < write < admin)
            return actual_permission_level == required_permission
        return False

    def read_file_securely(self, user_id, file_path):
        if not os.path.exists(file_path):
            return "Error: File not found."

        if self._check_permission(user_id, file_path, required_permission='read'):
            try:
                with open(file_path, 'r') as f:
                    return f.read()
            except IOError as e:
                return f"Error reading file: {e}"
        else:
            return "Permission Denied."

